import re
from collections import defaultdict
import sqlite3

# Load California patents data
file_path = 'file_storage/functions.query_db:10.json'
with open(file_path, 'r') as f:
    cal_pats = json.load(f)

# Step 1: Extract all cited publication numbers from California patents
cited_publications = set()
cal_pub_to_citations = defaultdict(list)  # Map California pub number to its citations

for patent in cal_pats:
    patents_info = patent.get('Patents_info', '')
    citation_str = patent.get('citation', '[]')

    # Extract California patent's own publication number
    cal_pub_match = re.search(r'(?:pub\. number |publication number )([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)
    if cal_pub_match:
        cal_pub_num = cal_pub_match.group(1)
    else:
        # Extract from Patents_info
        pub_matches = re.findall(r'([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)
        cal_pub_num = pub_matches[1] if len(pub_matches) > 1 else pub_matches[0] if pub_matches else None

    if citation_str and citation_str != '[]':
        try:
            citations = json.loads(citation_str)
            for cite in citations:
                pub_num = cite.get('publication_number')
                if pub_num:
                    cited_publications.add(pub_num)
                    if cal_pub_num:
                        cal_pub_to_citations[cal_pub_num].append(pub_num)
        except:
            pass

print('__RESULT__:')
print(json.dumps({
    'num_cal_pats': len(cal_pats),
    'num_cited_pubs': len(cited_publications),
    'sample_cited': list(cited_publications)[:10]
}))"}

{"code": "import json
import re

# Load California patents data
file_path_cal = 'file_storage/functions.query_db:10.json'
with open(file_path_cal, 'r') as f:
    cal_pats = json.load(f)

# Extract California patent data: publication number -> {cpc_codes, assignee}
cal_pat_data = {}

for patent in cal_pats:
    patents_info = patent.get('Patents_info', '')
    cpc_str = patent.get('cpc', '[]')

    # Extract publication number
    pub_match = re.search(r'(?:pub\. number |publication number )([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)
    if pub_match:
        pub_num = pub_match.group(1)
    else:
        # Fallback: find any publication number pattern
        matches = re.findall(r'([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)
        pub_num = matches[1] if len(matches) > 1 else matches[0] if matches else None

    if not pub_num:
        continue

    # Extract CPC codes
    cpc_codes = []
    try:
        if cpc_str and cpc_str != '[]':
            cpc_list = json.loads(cpc_str)
            for cpc_item in cpc_list:
                if 'code' in cpc_item:
                    # Get the subclass (first 4 characters + first letter after dash)
                    code = cpc_item['code']
                    # Extract subclass like Y02B from Y02B30/00
                    subclass_match = re.match(r'([A-Z][0-9][A-Z0-9]{2})', code)
                    if subclass_match:
                        cpc_codes.append(subclass_match.group(1))
    except:
        pass

    # Extract assignee (should be UNIV CALIFORNIA)
    assignee_match = re.search(r'(?:owned by|assigned to|holds the).*?([A-Z][A-Z\s]+)', patents_info)
    assignee = assignee_match.group(1).strip() if assignee_match else 'UNIV CALIFORNIA'

    if 'UNIV CALIFORNIA' in assignee:
        cal_pat_data[pub_num] = {
            'cpc_subclasses': list(set(cpc_codes)),  # Unique subclasses
            'assignee': 'UNIV CALIFORNIA'
        }

print('__RESULT__:')
print(json.dumps({
    'total_cal_pats': len(cal_pats),
    'valid_cal_pats': len(cal_pat_data),
    'sample_data': {k: cal_pat_data[k] for k in list(cal_pat_data.keys())[:3]}
}))"}

