with open(file_path_cal, 'r') as f:
    cal_pats = json.load(f)

# Extract California patent data: publication number -> cpc_codes
cal_pat_cpc = {}

for patent in cal_pats:
    patents_info = patent.get('Patents_info', '')
    cpc_str = patent.get('cpc', '[]')

    # Extract publication number - more robust pattern
    pub_match = re.search(r'pub\. number ([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)
    if not pub_match:
        pub_match = re.search(r'publication number ([A-Z]{2}-[A-Z0-9]+-[A-Z][0-9]?)', patents_info)

    if pub_match:
        pub_num = pub_match.group(1)
    else:
        continue

    # Extract CPC codes - fix the parsing
    cpc_codes = []
    try:
        if cpc_str and cpc_str.strip() != '[]':
            # The CPC field contains JSON-like data but with single quotes
            cpc_str_clean = cpc_str.replace("'", '"')
            cpc_list = json.loads(cpc_str_clean)
            for cpc_item in cpc_list:
                if isinstance(cpc_item, dict) and 'code' in cpc_item:
                    code = cpc_item['code']
                    # Extract subclass (e.g., Y02B from Y02B30/00)
                    subclass_match = re.match(r'([A-Z][0-9][A-Z0-9]{2})', code)
                    if subclass_match:
                        cpc_codes.append(subclass_match.group(1))
    except Exception as e:
        pass

    if cpc_codes:
        cal_pat_cpc[pub_num] = cpc_codes

print('__RESULT__:')
print(json.dumps({
    'total_cal_pats': len(cal_pats),
    'pats_with_cpc': len(cal_pat_cpc),
    'sample_cpc_data': {k: cal_pat_cpc[k] for k in list(cal_pat_cpc.keys())[:5]}
}))"}

